static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    VanillaRnnHiddenCustomTilingData tiling;

    const gert::StorageShape *x_shape = context->GetInputShape(0);
    const gert::StorageShape *w_i2h_shape = context->GetInputShape(2);
    const gert::StorageShape *w_h2o_shape = context->GetInputShape(4);

    uint32_t batchSize = x_shape->GetStorageShape().GetDim(0);
    uint32_t inputSize = x_shape->GetStorageShape().GetDim(1);
    uint32_t hiddenSize = w_i2h_shape->GetStorageShape().GetDim(0);
    uint32_t outputSize = w_h2o_shape->GetStorageShape().GetDim(0);

    uint32_t blockDim = (batchSize < 8) ? batchSize : 8;
    context->SetBlockDim(blockDim);

    tiling.set_batchSize(batchSize);
    tiling.set_inputSize(inputSize);
    tiling.set_hiddenSize(hiddenSize);
    tiling.set_outputSize(outputSize);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}
} // namespace optiling

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_h2o_shape = context->GetInputShape(4);
    const gert::Shape *w_i2h_shape = context->GetInputShape(2);

    // y shape: [batchSize, outputSize]
    gert::Shape *y_shape = context->GetOutputShape(0);
    y_shape->SetDimNum(2);
    y_shape->SetDim(0, x_shape->GetDim(0));
    y_shape->SetDim(1, w_h2o_shape->GetDim(0));

    // h_new shape: [batchSize, hiddenSize]
    gert::Shape *h_new_shape = context->GetOutputShape(1);
    h_new_shape->SetDimNum(2);
    h_new_shape->SetDim(0, x_shape->GetDim(0));
    h_new_shape->SetDim(1, w_i2h_shape->GetDim(0));

    return GRAPH_SUCCESS;
}

